<?php session_start(); require 'includes/header.php'; require_login();
if($_SERVER['REQUEST_METHOD']==='POST' && can_manage()){ $pdo->beginTransaction(); $st=$pdo->prepare('INSERT INTO stock_in(item_id,supplier_id,qty,unit_price,ref_no,received_date,received_by,remarks) VALUES(?,?,?,?,?,?,?,?)'); $st->execute([$_POST['item_id'],$_POST['supplier_id']?:null,$_POST['qty'],$_POST['unit_price'],$_POST['ref_no'],$_POST['received_date'],$_SESSION['user']['id'],$_POST['remarks']]); $pdo->prepare('UPDATE items SET current_stock=current_stock+?, unit_price=? WHERE id=?')->execute([$_POST['qty'],$_POST['unit_price'],$_POST['item_id']]); $pdo->commit(); log_action($pdo,'Stock In','Qty '.$_POST['qty']); header('Location:stock_in.php'); exit; }
$items=$pdo->query('SELECT * FROM items ORDER BY name')->fetchAll(); $sup=$pdo->query('SELECT * FROM suppliers ORDER BY name')->fetchAll(); $rows=$pdo->query('SELECT s.*,i.name item,sp.name supplier,u.full_name user FROM stock_in s JOIN items i ON i.id=s.item_id LEFT JOIN suppliers sp ON sp.id=s.supplier_id LEFT JOIN users u ON u.id=s.received_by ORDER BY s.id DESC LIMIT 100')->fetchAll();
?><h1>Stock In</h1><div class="card"><form method="post" class="formgrid"><select name="item_id" required><option value="">Select Item</option><?php foreach($items as $i) echo '<option value="'.$i['id'].'">'.e($i['name']).'</option>'; ?></select><select name="supplier_id"><option value="">Supplier</option><?php foreach($sup as $s) echo '<option value="'.$s['id'].'">'.e($s['name']).'</option>'; ?></select><input name="qty" type="number" step="0.01" placeholder="Quantity" required><input name="unit_price" type="number" step="0.01" placeholder="Unit Price"><input name="ref_no" placeholder="Invoice/Voucher No"><input name="received_date" type="date" value="<?=date('Y-m-d')?>"><textarea name="remarks" placeholder="Remarks"></textarea><button>Save Stock In</button></form></div><div class="card"><table id="tbl"><tr><th>Date</th><th>Item</th><th>Qty</th><th>Supplier</th><th>Ref</th><th>By</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['received_date'])?></td><td><?=e($r['item'])?></td><td><?=e($r['qty'])?></td><td><?=e($r['supplier'])?></td><td><?=e($r['ref_no'])?></td><td><?=e($r['user'])?></td></tr><?php endforeach ?></table></div><?php require 'includes/footer.php'; ?>
